class Query:
    @strawberry.field
    def products(
        self,
        name: Optional[str] = None,
        min_price: Optional[float] = None,
        max_price: Optional[float] = None,
        category_id: Optional[int] = None,
        seller_id: Optional[int] = None,
    ) -> List[Product]:
        db = SessionLocal()
        try:
            query = db.query(ProductModel).options(
                joinedload(ProductModel.reviews),
                joinedload(ProductModel.seller).joinedload(SellerModel.products),
                joinedload(ProductModel.categories).joinedload(CategoryModel.children),
                joinedload(ProductModel.images),
            )

            if name:
                query = query.filter(ProductModel.name.ilike(f"%{name}%"))
            if min_price is not None:
                query = query.filter(ProductModel.price >= min_price)
            if max_price is not None:
                query = query.filter(ProductModel.price <= max_price)
            if seller_id is not None:
                query = query.filter(ProductModel.seller_id == seller_id)
            if category_id is not None:
                query = query.join(ProductModel.categories).filter(
                    CategoryModel.id == category_id
                )

            products = query.all()
            return [Product.from_model(p) for p in products]
        finally:
            db.close()

