@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_product(self, input: ProductInput) -> Product:
        db = SessionLocal()
        try:
            product = ProductModel(
                name=input.name,
                description=input.description,
                price=input.price,
                seller_id=input.seller_id,
            )

            if input.category_ids:
                categories = (
                    db.query(CategoryModel)
                    .filter(CategoryModel.id.in_(input.category_ids))
                    .all()
                )
                product.categories = categories

            db.add(product)
            db.commit()
            db.refresh(product)

            # Re-query with eager loading
            product = (
                db.query(ProductModel)
                .options(
                    joinedload(ProductModel.reviews),
                    joinedload(ProductModel.seller),
                    joinedload(ProductModel.categories),
                    joinedload(ProductModel.images),
                )
                .filter(ProductModel.id == product.id)
                .first()
            )
            return Product.from_model(product)
        finally:
            db.close()

